75	      method: 'POST',
76	      headers: { 'Content-Type': 'application/json' },
77	      body: JSON.stringify({ email }),
78	    });
79	    const data = await res.json() as { url?: string };
80	    if (data?.url) {
81	      window.location.href = data.url;
82	    } else {
83	      window.location.href = '/demo';
84	    }
85	  } catch {
86	    window.location.href = '/demo';
87	  }
88	}
