368	export function DemoPage() {
369	  const [postcode, setPostcode] = useState('B14 7QH');
370	  const [trade, setTrade] = useState('plumbing');
371	  const [loading, setLoading] = useState(false);
372	  const [scanError, setScanError] = useState('');
373	  const [leads, setLeads] = useState<Lead[]>([]);
374	  const [summary, setSummary] = useState<{ total?: number; region?: string; outward?: string }>({});
375	  const [email, setEmail] = useState('');
376	  const [emailUnlocked, setEmailUnlocked] = useState(false);
377	  const [emailSubmitting, setEmailSubmitting] = useState(false);
378	  const [emailError, setEmailError] = useState('');
379	
380	  const runScan = async () => {
381	    setLoading(true);
382	    setScanError('');
383	    setEmailUnlocked(false);
384	    try {
385	      const res = await fetch('/api/leads/scan', {
386	        method: 'POST',
387	        headers: { 'Content-Type': 'application/json' },
388	        body: JSON.stringify({ postcode, trade, tier: 'paid' }),
389	      });
390	
391	      const ct = res.headers.get('content-type') ?? '';
392	      if (!ct.includes('application/json')) throw new Error('Scan warming up.');
393	
394	      const payload: ScanPayload = await res.json();
395	      if (!res.ok) throw new Error(payload.error ?? 'Scan failed.');
396	
397	      const mapped = Array.isArray(payload.leads)
398	        ? payload.leads.slice(0, 10).map((l) => ({
399	            id: l.id,
400	            title: l.title,
401	            location: l.location,
402	            estimatedValue: l.estimatedValue,
403	            urgency: l.urgency,
404	            source: l.source === 'Fallback Feed' ? 'JobFilter Direct' : (l.source || 'JobFilter Direct'),
405	            sourceConfidence: l.sourceConfidence,
406	            score: l.score,
407	          }))
408	        : [];
409	
410	      setLeads(mapped.length ? mapped : shuffleLeads(FALLBACK_POOL).slice(0, 7));
411	      setSummary({ total: payload.total, region: payload.region, outward: payload.outward });
412	    } catch {
413	      setLeads(shuffleLeads(FALLBACK_POOL).slice(0, 7));
414	      setSummary({});
415	      setScanError('Showing sample leads — live scan varies by area and trade.');
416	    } finally {
417	      setLoading(false);
418	    }
419	  };
420	
421	  const submitEmail = async () => {
422	    setEmailError('');
423	    if (!email.includes('@')) { setEmailError('Enter a valid email address.'); return; }
424	    setEmailSubmitting(true);
425	    try {
426	      await fetch('/api/waitlist', {
427	        method: 'POST',
428	        headers: { 'Content-Type': 'application/json' },
429	        body: JSON.stringify({ email, plan: 'free', postcode, trade }),
430	      });
431	    } catch { /* best effort — log on server */ }
432	    setEmailUnlocked(true);
433	    setEmailSubmitting(false);
434	  };
435	
436	  useEffect(() => { void runScan(); }, []); // eslint-disable-line react-hooks/exhaustive-deps
437	
438	  const freeLeads   = useMemo(() => leads.slice(0, 2), [leads]);
439	  const lockedLeads = useMemo(() => leads.slice(2),    [leads]);
440	
441	  return (
442	    <Shell>
443	      <main className="px-4 py-8">
444	        <div className="mx-auto max-w-4xl">
445	
